#define EXITHDPLIB_ERROR   (0xF5F5F5F5UL)

/*!< EXITHDPLIB pointer function structure address definition */
#define EXITHDPLIB_PFUNC_BASE EXITHDPLIB_SYS_FLASH_PFUNC_START
#define EXITHDPLIB_PFUNC      ((EXITHDPLIB_pFunc_TypeDef *)EXITHDPLIB_PFUNC_BASE)

/**
  * @brief  Prototype of EXITHDPLIB JumpHDPLvl2/3 Functions.
  * @detail This function close the requested hdp area passed in input
  *         parameter and jump to the reset handler present within the
  *         Vector table. The function does not return on successful execution.
  * @param  VectorTableAddr: Address of the next vector table to apply.
  * @param  MPUIndex: MPU region index to enable before jumping.
  * @retval EXITHDPLIB_ERROR on error, otherwise does not return.
  */
typedef uint32_t (*EXITHDPLIB_JumpHDP_TypeDef)(uint32_t VectorTableAddr, uint32_t MPUIndex);

/**
  * @brief  EXITHDPLIB function pointer structure
  */
typedef struct
{
  uint32_t                   Reserved[3];    /*!< Address offset: 0x00 */
  EXITHDPLIB_JumpHDP_TypeDef JumpHDPLvl2;    /*!< Address offset: 0x0C */
  EXITHDPLIB_JumpHDP_TypeDef JumpHDPLvl3;    /*!< Address offset: 0x10 */
} EXITHDPLIB_pFunc_TypeDef;

