#define HASH_CR_ALGO_Msk     (0xFUL << HASH_CR_ALGO_Pos)       /*!< 0x001E0000 */
#define HASH_CR_ALGO         HASH_CR_ALGO_Msk                  /*!< Algorithm selection */
