#define HASH_SR_NBWP_Msk     (0x1FUL << HASH_SR_NBWP_Pos)      /*!< 0x00003E00 */
#define HASH_SR_NBWP         HASH_SR_NBWP_Msk                  /*!< Number of words already pushed */
