#define HASH_SR_NBWP_3       (0x8UL << HASH_SR_NBWP_Pos)       /*!< 0x00001000 */
#define HASH_SR_NBWP_4       (0x10UL << HASH_SR_NBWP_Pos)      /*!< 0x00002000 */
#define HASH_SR_DINNE_Pos    (15U)
#define HASH_SR_DINNE_Msk    (0x1UL << HASH_SR_DINNE_Pos)      /*!< 0x00008000 */
#define HASH_SR_DINNE        HASH_SR_DINNE_Msk                 /*!< DIN not empty */
#define HASH_SR_NBWE_Pos     (16U)
#define HASH_SR_NBWE_Msk     (0x1FUL << HASH_SR_NBWE_Pos)      /*!< 0x001F0000 */
#define HASH_SR_NBWE         HASH_SR_NBWE_Msk                  /*!< Number of words expected */
#define HASH_SR_NBWE_0       (0x1UL << HASH_SR_NBWE_Pos)       /*!< 0x00010000 */
#define HASH_SR_NBWE_1       (0x2UL << HASH_SR_NBWE_Pos)       /*!< 0x00020000 */
#define HASH_SR_NBWE_2       (0x4UL << HASH_SR_NBWE_Pos)       /*!< 0x00040000 */
